import React from 'react';
import { Link } from 'react-router-dom';

const Hero = ({ movie }) => {
  if (!movie) return null;

  return (
    <div className="relative w-full h-[70vh] min-h-[500px] mb-12 overflow-hidden rounded-bl-[4rem]">
      <div className="absolute inset-0">
        <img 
          src={movie.poster} 
          alt={movie.title}
          className="w-full h-full object-cover object-top opacity-70"
          onError={(e) => {
             e.target.src = 'https://images.unsplash.com/photo-1536440136628-849c177e76a1?ixlib=rb-4.0.3&auto=format&fit=crop&w=1925&q=80';
          }}
        />
        {/* Gradient Overlay */}
        <div className="absolute inset-0 bg-gradient-to-t from-stream-dark via-stream-dark/50 to-transparent"></div>
        <div className="absolute inset-0 bg-gradient-to-r from-stream-dark via-stream-dark/70 to-transparent"></div>
      </div>

      <div className="relative h-full container mx-auto px-6 md:px-12 flex flex-col justify-end pb-20 z-10 animate-fade-in">
        <div className="max-w-2xl">
          <div className="flex items-center space-x-4 mb-4">
            <span className="px-3 py-1 bg-stream-card text-white text-xs font-bold rounded-full border border-white/10 backdrop-blur-md">
              {movie.type === 'series' ? 'SERIE' : 'PELÍCULA'}
            </span>
            <span className="text-gray-300 text-sm font-medium">{movie.year}</span>
          </div>

          <h1 className="text-5xl md:text-7xl font-extrabold text-white mb-4 leading-tight tracking-tight shadow-sm">
            {movie.title}
          </h1>

          <p className="text-gray-300 text-lg mb-8 line-clamp-3">
            {movie.description || 'Una emocionante historia llena de acción, drama y aventuras. No te pierdas esta increíble entrega directamente en RaulFlix.'}
          </p>

          <div className="flex flex-wrap gap-4">
            <Link 
              to={`/movie/${movie.id}`}
              className="px-8 py-3 bg-stream-red hover:bg-rose-700 text-white font-bold rounded-lg transition-transform hover:scale-105 flex items-center gap-2"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" />
              </svg>
              Reproducir
            </Link>

            <button className="px-8 py-3 bg-white/10 hover:bg-white/20 text-white font-semibold rounded-lg backdrop-blur-sm transition-all border border-white/10 flex items-center gap-2">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              Más info
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Hero;
